#include <bits/stdc++.h>
#define int long long
#define mk make_pair
#define PII pair<int,int>
#define FOR(i,j,k) for(int i=(j);i<=(k);++i)
#define ROF(i,j,k) for(int i=(j);i>=(k);--i)
#define FOI(a,b) for(auto a : b)
#define wh while
#define inf 0x3f3f3f3f3f3f3f3f
#define IOS ios::sync_with_stdio(false);
#define snd second
#define fst first
#define pb push_back
#define CI const int
#define NP namespace
using NP std;
int quickpow(int a,int b)
{
	int ans=1;
	wh(b)
	{
		if(b&1)ans=ans*a;
        a=a*a;
		b>>=1;
	}
	return ans;
}
CI MAXM=3e3+5;
int n,m,f[MAXM][MAXM];
vector<PII> e[MAXM];
int dfs(int u)
{
	f[u][0]=0;
	if(u>n-m)return 1;
	int ans=0;
	FOI(s,e[u])
	{
		int t=dfs(s.fst);
		ans+=t;
		ROF(j,ans,0)
    		FOR(i,0,t)
        		if(j-i>=0)
            		f[u][j]=max(f[u][j],f[u][j-i]+f[s.fst][i]-s.snd);//树上背包
	}
	return ans;
}
signed main(void)
{
	memset(f,-0x3f,sizeof f);
	cin>>n>>m;
	FOR(i,1,n-m)
	{
		int k;
        cin>>k;
		FOR(j,1,k)
		{
			int a,c;
            cin>>a>>c;
			e[i].pb({a,c});//单向图
		}
	}
	FOR(i,1,m)cin>>f[i+n-m][1];
	dfs(1);
	ROF(i,m,0)
	{
		if(f[1][i]>=0)
		{
			cout<<i;
			break;
		}
	}
	return false;
}
